@app.route('/callback')
def callback():
    # Check for error responses from the authorization server
    error = request.args.get('error')
    if error:
        error_description = request.args.get('error_description', 'Unknown error')
        app.logger.warning("OAuth authorization error: %s - %s", error, error_description)
        abort(403, description="Authorization was denied or failed.")

    # Validate the state parameter to prevent CSRF attacks
    returned_state = request.args.get('state')
